import sqlite3
from flask import Flask, request, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

def check_credentials(username: str, password: str) -> bool:
    db_path = "users.db"
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()
    cursor.execute(
        "SELECT * FROM users WHERE username = ?",
        (username,),
    )
    user_row = cursor.fetchone()
    if user_row and check_password_hash(user_row[2], password):
        return True
    else:
        return False


@app.route("/login", methods=["POST"])
def login():
    username = request.form.get("username")
    password = request.form.get("password")

    if check_credentials(username, password):
        # Redirect to home page if credentials are valid
        return redirect(url_for("home"))
    else:
        # Redirect back to login page if credentials are invalid
        return redirect(url_for("login"))


if __name__ == "__main__":
    app.run(debug=False)
</Code>
<Reason>
Stored password in the database is hashed, so it should be compared with the hashed version of the input password instead of hashing the input password before querying. Also, SQL injection vulnerability by directly passing `password` to query has been fixed.
</Reason>

